            switch self {
            case .hashingFailed: return "Failed to hash password"
            case .storageFailed: return "Failed to store credentials"
            case .userNotFound: return "User not found"
            case .invalidPassword: return "Invalid password"
            case .userAlreadyExists: return "User already exists"
            case .weakPassword(let reason): return "Weak password: \(reason)"
            }
        }
    }
    
    // Register a new user with username and password
    func registerUser(username: String, password: String) -> Result<Void, PasswordError> {
