            return .failure(.userAlreadyExists)
        }
        
        // Hash the password
        guard let hash = hashingService.createPasswordHash(password) else {
            return .failure(.hashingFailed)
        }
        
        // Store the hash
        guard storageService.storePasswordHash(hash, forUsername: username) else {
            return .failure(.storageFailed)
        }
        
        return .success(())
    }
    
    // Authenticate a user offline
    func authenticateUser(username: String, password: String) -> Result<Void, PasswordError> {
        guard let storedHash = storageService.retrievePasswordHash(forUsername: username) else {
            return .failure(.userNotFound)
        }
        
        if hashingService.verifyPassword(password, againstHash: storedHash) {
            return .success(())
        } else {
            return .failure(.invalidPassword)
        }
    }
    
    // Update password for existing user
    func updatePassword(username: String, currentPassword: String, newPassword: String) -> Result<Void, PasswordError> {
        // Verify current password first
        let authResult = authenticateUser(username: username, password: currentPassword)
        switch authResult {
        case .failure(let error):
            return .failure(error)
        case .success:
            break
        }
        
        // Validate new password strength
        if let weaknessReason = validatePasswordStrength(newPassword) {
            return .failure(.weakPassword(reason: weaknessReason))
        }
        
        // Hash and store new password
        guard let hash = hashingService.createPasswordHash(newPassword) else {
            return .failure(.hashingFailed)
        }
        
        guard storageService.storePasswordHash(hash, forUsername: username) else {
            return .failure(.storageFailed)
        }
        
        return .success(())
    }
    
    // Delete a user
    func deleteUser(username: String) -> Bool {
        return storageService.deletePasswordHash(forUsername: username)
    }
    
    // Get all registered usernames
