// MARK: - Login Rate Limiter (Brute Force Protection)

class LoginRateLimiter {
    
    static let shared = LoginRateLimiter()
    
    private var failedAttempts: [String: (count: Int, lastAttempt: Date)] = [:]
    private let maxAttempts = 5
    private let lockoutDuration: TimeInterval = 300 // 5 minutes
    private let queue = DispatchQueue(label: "com.passwordstorage.ratelimiter", attributes: .concurrent)
    
    private init() {}
    
    func canAttemptLogin(forUsername username: String) -> (allowed: Bool, remainingLockout: TimeInterval?) {
        var result: (allowed: Bool, remainingLockout: TimeInterval?) = (true, nil)
        
        queue.sync {
            guard let record = failedAttempts[username] else {
                result = (true, nil)
                return
            }
            
            let timeSinceLastAttempt = Date().timeIntervalSince(record.lastAttempt)
            
            if record.count >= maxAttempts && timeSinceLastAttempt < lockoutDuration {
                let remaining = lockoutDuration - timeSinceLastAttempt
                result = (false, remaining)
            } else if timeSinceLastAttempt >= lockoutDuration {
                result = (true, nil)
            } else {
                result = (true, nil)
            }
        }
        
        return result
    }
    
    func recordFailedAttempt(forUsername username: String) {
        queue.async(flags: .barrier) {
            if var record = self.failedAttempts[username] {
                let timeSinceLastAttempt = Date().timeIntervalSince(record.lastAttempt)
                if timeSinceLastAttempt >= self.lockoutDuration {
                    // Reset after lockout period
                    self.failedAttempts[username] = (count: 1, lastAttempt: Date())
                } else {
                    record.count += 1
                    record.lastAttempt = Date()
                    self.failedAttempts[username] = record
                }
            } else {
                self.failedAttempts[username] = (count: 1, lastAttempt: Date())
            }
        }
    }
    
    func recordSuccessfulLogin(forUsername username: String) {
        queue.async(flags: .barrier) {
            self.failedAttempts.removeValue(forKey: username)
        }
    }
    
    func resetAllAttempts() {
        queue.async(flags: .barrier) {
            self.failedAttempts.removeAll()
        }
    }
}

