            actionButton.setTitle("Register", for: .normal)
            actionButton.backgroundColor = UIColor(red: 0.2, green: 0.7, blue: 0.3, alpha: 1.0)
            
        case 2: // Update Password
            passwordTextField.isHidden = true
            currentPasswordTextField.isHidden = false
            newPasswordTextField.isHidden = false
            actionButton.setTitle("Update Password", for: .normal)
            actionButton.backgroundColor = UIColor(red: 1.0, green: 0.6, blue: 0.0, alpha: 1.0)
            
        default:
