    private func clearFields() {
        usernameTextField.text = ""
        passwordTextField.text = ""
        currentPasswordTextField.text = ""
        newPasswordTextField.text = ""
    }
    
    @objc private func actionButtonTapped() {
        dismissKeyboard()
        
        guard let username = usernameTextField.text, !username.isEmpty else {
            showStatus("Please enter a username", isError: true)
            return
        }
        
        let selectedIndex = segmentedControl.selectedSegmentIndex
        
        switch selectedIndex {
        case 0:
            performLogin(username: username)
        case 1:
            performRegistration(username: username)
        case 2:
            performPasswordUpdate(username: username)
        default:
            break
        }
    }
    
    private func performLogin(username: String) {
        guard let password = passwordTextField.text, !password.isEmpty else {
            showStatus("Please enter a password", isError: true)
            return
        }
        
        // Check rate limiting
        let rateCheck = rateLimiter.canAttemptLogin(forUsername: username)
        if !rateCheck.allowed {
            let remaining = Int(rateCheck.remainingLockout ?? 0)
            showStatus("Account locked. Try again in \(remaining) seconds.", isError: true)
            return
        }
        
        // Perform authentication on background thread to avoid blocking UI
        actionButton.isEnabled = false
        showStatus("Authenticating...", isError: false)
        
        DispatchQueue.global(qos: .userInitiated).async { [weak self] in
            let result = self?.passwordManager.authenticateUser(username: username, password: password)
            
            DispatchQueue.main.async {
                self?.actionButton.isEnabled = true
                
                switch result {
                case .success:
                    self?.rateLimiter.recordSuccessfulLogin(forUsername: username)
                    self?.showStatus("✅ Login successful! Welcome, \(username)!", isError: false)
                case .failure(let error):
                    self?.rateLimiter.recordFailedAttempt(forUsername: username)
                    self?.showStatus("❌ \(error.description)", isError: true)
                case .none:
                    self?.showStatus("❌ An unexpected error occurred", isError: true)
                }
            }
        }
    }
    
    private func performRegistration(username: String) {
        guard let password = passwordTextField.text, !password.isEmpty else {
            showStatus("Please enter a password", isError: true)
            return
        }
        
        actionButton.isEnabled = false
        showStatus("Registering...", isError: false)
        
        DispatchQueue.global(qos: .userInitiated).async { [weak self] in
            let result = self?.passwordManager.registerUser(username: username, password: password)
            
            DispatchQueue.main.async {
                self?.actionButton.isEnabled = true
                
                switch result {
                case .success:
                    self?.showStatus("✅ Registration successful for \(username)!", isError: false)
                    self?.clearFields()
                case .failure(let error):
                    self?.showStatus("❌ \(error.description)", isError: true)
                case .none:
                    self?.showStatus("❌ An unexpected error occurred", isError: true)
                }
            }
        }
    }
    
    private func performPasswordUpdate(username: String) {
        guard let currentPassword = currentPasswordTextField.text, !currentPassword.isEmpty else {
            showStatus("Please enter your current password", isError: true)
            return
        }
        
        guard let newPassword = newPasswordTextField.text, !newPassword.isEmpty else {
            showStatus("Please enter a new password", isError: true)
            return
        }
        
        actionButton.isEnabled = false
        showStatus("Updating password...", isError: false)
        
        DispatchQueue.global(qos: .userInitiated).async { [weak self] in
            let result = self?.passwordManager.updatePassword(
                username: username,
                currentPassword: currentPassword,
                newPassword: newPassword
            )
            
            DispatchQueue.main.async {
                self?.actionButton.isEnabled = true
                
                switch result {
                case .success:
                    self?.showStatus("✅ Password updated successfully for \(username)!", isError: false)
                    self?.clearFields()
                case .failure(let error):
                    self?.showStatus("❌ \(error.description)", isError: true)
                case .none:
                    self?.showStatus("❌ An unexpected error occurred", isError: true)
                }
            }
        }
    }
    
    private func showStatus(_ message: String, isError: Bool) {
        statusLabel.text = message
        statusLabel.textColor = isError ? .red : UIColor(red: 0.0, green: 0.5, blue: 0.0, alpha: 1.0)
    }
    
    @objc private func showUserList() {
        let users = passwordManager.getAllUsers()
        
        let alert = UIAlertController(
            title: "Registered Users",
            message: users.isEmpty ? "No users registered yet." : users.joined(separator: "\n"),
            preferredStyle: .alert
        )
        
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        
        if !users.isEmpty {
            alert.addAction(UIAlertAction(title: "Delete All", style: .destructive) { [weak self] _ in
                self?.confirmDeleteAll()
            })
        }
        
        present(alert, animated: true)
    }
    
    private func confirmDeleteAll() {
        let alert = UIAlertController(
            title: "Confirm Delete",
            message: "Are you sure you want to delete all stored credentials? This cannot be undone.",
            preferredStyle: .alert
        )
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        alert.addAction(UIAlertAction(title: "Delete All", style: .destructive) { [weak self] _ in
            if self?.passwordManager.deleteAllUsers() == true {
                self?.showStatus("All credentials deleted.", isError: false)
            } else {
                self?.showStatus("Failed to delete credentials.", isError: true)
            }
        })
        
        present(alert, animated: true)
    }
    
    @objc private func dismissKeyboard() {
        view.endEditing(true)
    }
}

